  <text x="20" y="26" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Le Parcours de Polymarket Vers l'Approbation du Trading sur Marge</text>
  <text x="20" y="46" fill="#71717a" font-size="13" font-family="sans-serif">Chronologie · Procédure CFTC/NFA</text>
  <line x1="55" y1="80" x2="55" y2="330" stroke="rgba(255,255,255,.15)" stroke-width="2"/>
  <circle cx="55" cy="90" r="7" fill="#4ade80"/>
  <text x="75" y="86" fill="#fafafa" font-size="13.5" font-weight="700" font-family="sans-serif">2025</text>
  <text x="75" y="106" fill="#a1a1aa" font-size="13" font-family="sans-serif">Acquiert QCX LLC pour 112 M$ — obtient une bourse enregistrée à la CFTC</text>
  <circle cx="55" cy="150" r="7" fill="#4ade80"/>
